_.executor.ExecutorFunctionType = class extends _.Type {

    constructor(inputs, results, trailingVariadic) {
        super(null);
        this.inputs = inputs;
        this.results = results;
        this.trailingVariadic = trailingVariadic;
    }

    static parse(parser) {
        parser.parseLess();
        parser.parseLParen();
        const inputs = [];
        let trailingVariadic = false;
        if (!parser.parseOptionalRParen()) {
            if (parser.parseOptionalEllipsis()) {
                trailingVariadic = true;
            } else {
                inputs.push(parser.parseType());
                while (parser.parseOptionalComma()) {
                    if (parser.parseOptionalEllipsis()) {
                        trailingVariadic = true;
                        break;
                    }
                    inputs.push(parser.parseType());
                }
            }
            parser.parseRParen();
        }
        parser.parseArrow();
        parser.parseLParen();
        const results = [];
        if (!parser.parseOptionalRParen()) {
            do {
                results.push(parser.parseType());
            } while (parser.parseOptionalComma());
            parser.parseRParen();
        }
        parser.parseGreater();
        return new _.executor.ExecutorFunctionType(inputs, results, trailingVariadic);
    }

    toString() {
        const input = this.inputs.map((t) => t.toString()).join(', ');
        const result = this.results.map((t) => t.toString()).join(', ');
        let variadic = '';
        if (this.trailingVariadic) {
            variadic = input ? ', ...' : '...';
        }
        return `!executor.func<(${input}${variadic}) -> (${result})>`;
    }
};

_.executor.ExecutorDialect = class extends _.Dialect {

    constructor(operations) {
        super(operations, 'executor');
        this.registerCustomType('Executor_Table', this.parseTable.bind(this));
        this.registerCustomDirective('ExecutorMixedIndices', this.parseExecutorMixedIndices.bind(this));
    }

    parseOperation(parser, result) {
        const op = result.name.getStringRef();
        if (op === 'executor.func') {
            parser.parseFunctionOp(result, true);
            return true;
        }
        return super.parseOperation(parser, result);
    }

    inferResultTypes(op, vars) {
        if (op.name.getStringRef() === 'executor.table.get') {
            // ExtractTableValueOp::inferReturnTypes
            const tableType = op.operands[0]?.type;
            const index = op.attributes.get('index');
            if (tableType instanceof _.executor.TableType && index !== undefined) {
                const idx = typeof index === 'number' ? index : parseInt(index, 10);
                if (idx >= 0 && idx < tableType.body.length) {
                    op.addTypes([tableType.body[idx]]);
                    return;
                }
            }
        }
        super.inferResultTypes(op, vars);
    }

    parseType(parser, dialect) {
        const mnemonic = parser.parseKeyword();
        if (mnemonic === 'table') {
            if (parser.parseOptionalLess()) {
                const body = [];
                if (!parser.parseOptionalGreater()) {
                    do {
                        const elementType = parser.parseType();
                        body.push(elementType);
                    } while (parser.parseOptionalComma());
                    parser.parseGreater();
                }
                return new _.executor.TableType(body);
            }
            return new _.executor.TableType([]);
        }
        if (mnemonic === 'ptr') {
            return _.executor.PointerType.parse(parser);
        }
        if (mnemonic === 'func') {
            return _.executor.ExecutorFunctionType.parse(parser);
        }
        return new _.Type(`!${dialect}.${mnemonic}`);
    }

    parseTable(parser) {
        if (parser.parseOptionalLess()) {
            const body = [];
            if (!parser.parseOptionalGreater()) {
                do {
                    const elementType = parser.parseType();
                    body.push(elementType);
                } while (parser.parseOptionalComma());
                parser.parseGreater();
            }
            return new _.executor.TableType(body);
        }
        return null;
    }

    parseExecutorMixedIndices(parser, op /*, args */) {
        const unresolvedOperands = [];
        do {
            const __mixedOp = parser.parseOptionalOperand();
            if (__mixedOp) {
                unresolvedOperands.push(__mixedOp);
            } else {
                parser.parseAttribute();
            }
        } while (parser.parseOptionalComma());
        for (const unresolved of unresolvedOperands) {
            parser.resolveOperand(unresolved, null, op.operands);
        }
    }
};

_.TFRTTestDialect = class extends _.Dialect {

    constructor(operations) {
        super(operations, 'tfrt_test');
        this.registerCustomDirective('OptionalLoc', this.parseOptionalLoc.bind(this));
        this.registerCustomDirective('DummyRegionRef', this.parseDummyRegionRef.bind(this));
        this.registerCustomDirective('DummySuccessorRef', this.parseDummySuccessorRef.bind(this));
    }

    parseOptionalLoc(parser, op, attrName = 'loc') {
        const loc = parser.parseOptionalLocationSpecifier();
        if (loc) {
            op.addAttribute(attrName, loc);
        } else {
            op.addAttribute(attrName, parser.getCurrentLocation());
        }
    }

    parseDummyRegionRef() {
    }

    parseDummySuccessorRef() {
    }

    parseOperation(parser, result) {
        const op = result.name.getStringRef();
        const opInfo = result.name.getRegisteredInfo();
        if (!opInfo) {
            return false;
        }
        if (opInfo.metadata.assemblyFormat === 'operands attr-dict') {
            const unresolvedOperands = parser.parseOperandList();
            parser.parseOptionalAttrDict(result.attributes);
            for (const unresolved of unresolvedOperands) {
                parser.resolveOperand(unresolved, null, result.operands);
            }
            this.inferResultTypes(result, new Map());
            return true;
        }
        if (op === 'tfrt_test.do.async') {
            const unresolvedOperands = parser.parseOperandList('none');
            if (unresolvedOperands.length > 0) {
                parser.resolveOperands(unresolvedOperands, unresolvedOperands.map(() => null), result.operands);
            }
            if (parser.parseOptionalColon()) {
                const type = parser.parseType();
                if (type && type.results) {
                    type.results.forEach((resultType) => {
                        result.addTypes([resultType]);
                    });
                }
            }
            parser.parseOptionalRegion(result.addRegion());
            return true;
        }
        if (op === 'tfrt_test.benchmark') {
            const __benchName = parser.parseOptionalString();
            if (__benchName !== null) {
                result.addAttribute('name', __benchName);
            }
            parser.parseLParen();
            let __benchOp = parser.parseOptionalOperand();
            while (__benchOp) {
                let type = null;
                if (parser.parseOptionalColon()) {
                    type = parser.parseType();
                }
                parser.resolveOperand(__benchOp, type, result.operands);
                if (!parser.parseOptionalComma()) {
                    break;
                }
                __benchOp = parser.parseOptionalOperand();
            }
            parser.parseRParen();
            for (let name = parser.parseOptionalKeyword(); name; name = parser.parseOptionalKeyword()) {
                parser.parseEqual();
                let value = null;
                const __intVal = parser.parseOptionalInteger();
                if (__intVal === null) {
                    const __strVal = parser.parseOptionalString();
                    if (__strVal === null) {
                        value = parser.parseKeyword();
                    } else {
                        value = __strVal;
                    }
                } else {
                    value = __intVal;
                }
                result.addAttribute(name, value);
                parser.parseOptionalComma();
            }
            parser.parseOptionalRegion(result.addRegion());
            result.addTypes([new _.Type('!tfrt.chain')]);
            return true;
        }
        return super.parseOperation(parser, result);
    }
};

